{
  "name": "@langchain/langsmith-pi-extension",
  "version": "0.0.1",
  "description": "LangSmith extension for Pi Coding Agent",
  "keywords": [
    "coding-agent",
    "langsmith",
    "pi",
    "pi-package"
  ],
  "license": "MIT",
  "author": "LangChain",
  "type": "module",
  "scripts": {},
  "dependencies": {
    "langsmith": "^0.6.0",
    "zod": "^4.4.3"
  },
  "devDependencies": {
    "@earendil-works/pi-ai": "^0.78.0",
    "@earendil-works/pi-coding-agent": "^0.78.0",
    "@types/node": "^25.6.0",
    "oxfmt": "^0.47.0",
    "vitest": "^4.1.8"
  },
  "pi": {
    "extensions": [
      "./src/index.ts"
    ]
  }
}

import type { ContextEvent, ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Client, RunTree } from "langsmith";

import { type Config, getConfig } from "./config";

const EXTENSION_NAME = "langsmith-pi-extension";
const STATUS_KEY = "langsmith";

const PARENT_DOTTED_ORDER_ENV = "LANGSMITH_PI_PARENT_DOTTED_ORDER";
const PARENT_BAGGAGE_ENV = "LANGSMITH_PI_PARENT_BAGGAGE";

interface PendingLlmRun {
  name: string;
  payload: unknown;
  metadata: Record<string, unknown>;
  providerResponses: Array<{ status: number; headers: Record<string, string> }>;
}

interface TraceContext {
  root: RunTree;
  turns: Map<number, RunTree>;

  currentTurn?: RunTree;
  currentLlm?: RunTree;
  pendingLlm?: PendingLlmRun;
  deferNextLlmToNextTurn: boolean;

  tools: Map<string, RunTree>;
  envRestores: Map<string, { dottedOrder?: string; baggage?: string }>;
}

type AgentMessage = ContextEvent["messages"][number];

type ExtractMessage<Role extends string> = AgentMessage extends infer T
  ? T extends { role: Role }
    ? T
    : never
  : never;

const isMessage = <Role extends string>(
  message: AgentMessage,
  role: Role,
): message is ExtractMessage<Role> => {
  return message.role === role;
};

const extractUsageMetadata = (message: AgentMessage): Record<string, unknown> | undefined => {
  if (!isMessage(message, "assistant")) return undefined;

  return {
    input_tokens: message.usage?.input,
    input_cost: message.usage?.cost?.input,

    output_tokens: message.usage?.output,
    output_cost: message.usage?.cost?.output,

    total_tokens: message.usage?.totalTokens,
    total_cost: message.usage?.cost?.total,
  };
};

async function startLlmRun(
  trace: TraceContext,
  parent: RunTree,
  pending: PendingLlmRun,
): Promise<RunTree> {
  const llm = parent.createChild({
    name: pending.name,
    run_type: "llm",
    inputs: { payload: pending.payload },
    metadata: pending.metadata,
  });

  trace.currentLlm = llm;
  await safePost(llm);
  return llm;
}

async function safePost(run: RunTree): Promise<void> {
  await run.postRun();
}

async function safeEnd(
  run: RunTree | undefined,
  params: {
    outputs?: Record<string, unknown>;
    error?: string;
    metadata?: Record<string, unknown>;
  },
): Promise<void> {
  await run?.end(params.outputs, params.error, undefined, params.metadata);
  await run?.patchRun();
}

function isPiSubagentChild(): boolean {
  return process.env.PI_SUBAGENT_CHILD === "1";
}

function subagentMetadata(): Record<string, unknown> {
  if (!isPiSubagentChild()) return {};
  return {
    piSubagent: true,
    subagentRunId: process.env.PI_SUBAGENT_RUN_ID,
    subagentAgent: process.env.PI_SUBAGENT_CHILD_AGENT,
    subagentIndex: process.env.PI_SUBAGENT_CHILD_INDEX,
    subagentDepth: process.env.PI_SUBAGENT_DEPTH,
  };
}

function parentRunFromEnv(client: Client): RunTree | undefined {
  const dottedOrder = process.env[PARENT_DOTTED_ORDER_ENV];
  if (!dottedOrder) return undefined;
  return RunTree.fromHeaders(
    { "langsmith-trace": dottedOrder, baggage: process.env[PARENT_BAGGAGE_ENV] ?? "" },
    { client },
  );
}

function createRootRun(
  client: Client,
  extensionConfig: Config,
  prompt: string,
  imageCount: number,
  cwd: string,
): RunTree {
  const config = {
    name: isPiSubagentChild()
      ? `Pi subagent run${process.env.PI_SUBAGENT_CHILD_AGENT ? `: ${process.env.PI_SUBAGENT_CHILD_AGENT}` : ""}`
      : "Pi agent run",
    run_type: "chain",
    project_name: extensionConfig.project,
    client,
    inputs: { prompt, imageCount },
    metadata: {
      ls_integration: EXTENSION_NAME,
      cwd,
      ...extensionConfig.metadata,
      ...subagentMetadata(),
    },
    tags: ["pi", "coding-agent", ...(isPiSubagentChild() ? ["pi-subagent"] : [])],
    replicas: extensionConfig.replicas?.map((replica) => ({
      ...(replica.api_url ? { apiUrl: replica.api_url } : {}),
      ...(replica.api_key ? { apiKey: replica.api_key } : {}),
      ...(replica.project ? { projectName: replica.project } : {}),
      ...(replica.updates ? { updates: replica.updates } : {}),
    })),
  };

  const parentRun = parentRunFromEnv(client);
  return parentRun ? parentRun.createChild(config) : new RunTree(config);
}

function setTraceParentEnv(trace: TraceContext, toolCallId: string, run: RunTree): void {
  const headers = run.toHeaders();
  trace.envRestores.set(toolCallId, {
    dottedOrder: process.env[PARENT_DOTTED_ORDER_ENV],
    baggage: process.env[PARENT_BAGGAGE_ENV],
  });
  process.env[PARENT_DOTTED_ORDER_ENV] = headers["langsmith-trace"];
  process.env[PARENT_BAGGAGE_ENV] = headers.baggage;
}

function restoreTraceParentEnv(trace: TraceContext, toolCallId: string): void {
  const previous = trace.envRestores.get(toolCallId);
  if (!previous) return;
  trace.envRestores.delete(toolCallId);
  if (previous.dottedOrder === undefined) delete process.env[PARENT_DOTTED_ORDER_ENV];
  else process.env[PARENT_DOTTED_ORDER_ENV] = previous.dottedOrder;
  if (previous.baggage === undefined) delete process.env[PARENT_BAGGAGE_ENV];
  else process.env[PARENT_BAGGAGE_ENV] = previous.baggage;
}

export default async function (pi: ExtensionAPI, options?: { client?: Client }) {
  const config = await getConfig();
  const enabled = config.enabled;

  const client = enabled
    ? (options?.client ?? new Client({ apiKey: config.api_key, apiUrl: config.api_url }))
    : undefined;

  let active: TraceContext | undefined;

  pi.on("session_start", async (_event, ctx) => {
    if (enabled) {
      ctx.ui.setStatus(STATUS_KEY, "LangSmith: tracing");
    } else {
      ctx.ui.setStatus(STATUS_KEY, "LangSmith: disabled");
    }
  });

  pi.registerCommand("langsmith-tracing", {
    description: "Show LangSmith tracing status for this Pi session",
    handler: async (_args, ctx) => {
      const message = enabled
        ? `LangSmith tracing is enabled${active ? ` (active trace ${active.root.id})` : ""}.`
        : "LangSmith tracing is disabled. Set TRACE_TO_LANGSMITH=true and configure LANGSMITH_PI_API_KEY (or LANGSMITH_PI_ENDPOINT for self-hosted) to enable it.";
      ctx.ui.notify(message, enabled ? "info" : "warning");
    },
  });

  if (!enabled || !client) return;
  pi.on("before_agent_start", async (event, ctx) => {
    if (active) {
      await safeEnd(active.root, {
        outputs: { interruptedByNextRun: true },
        error: "Trace replaced by a new Pi run",
      });
    }

    active = {
      root: createRootRun(client, config, event.prompt, event.images?.length ?? 0, ctx.cwd),
      turns: new Map(),
      deferNextLlmToNextTurn: false,
      tools: new Map(),
      envRestores: new Map(),
    };
    await safePost(active.root);
    ctx.ui.setStatus(STATUS_KEY, "LangSmith: tracing run");
  });

  pi.on("turn_start", async (event, ctx) => {
    console.log("turn_start", { turnIndex: event.turnIndex });

    if (!active) return;

    const turn = active.root.createChild({
      name: `Pi turn ${event.turnIndex}`,
      run_type: "chain",
      inputs: { turnIndex: event.turnIndex },
      metadata: {
        ls_provider: ctx.model?.provider,
        ls_model_name: ctx.model?.name?.toLocaleLowerCase(),
        timestamp: event.timestamp,
      },
    });
    active.turns.set(event.turnIndex, turn);
    active.currentTurn = turn;
    active.deferNextLlmToNextTurn = false;
    await safePost(turn);

    if (active.pendingLlm) {
      const pending = active.pendingLlm;
      active.pendingLlm = undefined;
      await startLlmRun(active, turn, pending);
    }
  });

  pi.on("before_provider_request", async (event, ctx) => {
    console.log("before_provider_request", {
      provider: ctx.model?.provider,
      name: ctx.model?.name,
    });
    if (!active) return;
    const pending = {
      name: ctx.model?.provider ?? ctx.model?.name?.toLocaleLowerCase() ?? "provider request",
      payload: event.payload,
      metadata: {
        ls_provider: ctx.model?.provider,
        ls_model_name: ctx.model?.name?.toLocaleLowerCase(),
      },
      providerResponses: [],
    };

    if (active.deferNextLlmToNextTurn) {
      active.pendingLlm = pending;
      return;
    }

    await startLlmRun(active, active.currentTurn ?? active.root, pending);
  });

  pi.on("after_provider_response", async (event) => {
    active?.pendingLlm?.providerResponses.push({ status: event.status, headers: event.headers });
  });

  pi.on("message_end", async (event) => {
    if (!active || event.message.role !== "assistant" || !active.currentLlm) return;
    const error =
      event.message.stopReason === "error"
        ? (event.message.errorMessage ?? "Assistant message ended with stopReason=error")
        : undefined;

    await safeEnd(active.currentLlm, {
      outputs: { message: event.message },
      error,
      metadata: {
        stop_reason: event.message.stopReason,
        usage_metadata: extractUsageMetadata(event.message),
      },
    });
    active.currentLlm = undefined;
    active.deferNextLlmToNextTurn = true;
  });

  pi.on("tool_execution_start", async (event) => {
    if (!active) return;
    const parent = active.currentTurn ?? active.root;
    const tool = parent.createChild({
      name: event.toolName,
      run_type: "tool",
      inputs: { toolCallId: event.toolCallId, args: event.args },
      metadata: { toolName: event.toolName, toolCallId: event.toolCallId },
    });
    active.tools.set(event.toolCallId, tool);
    if (event.toolName === "subagent") setTraceParentEnv(active, event.toolCallId, tool);
    await safePost(tool);
  });

  pi.on("tool_execution_update", async (event) => {
    const tool = active?.tools.get(event.toolCallId);
    if (!tool || !active) return;

    tool.addEvent({ name: "tool_update", kwargs: { partialResult: event.partialResult } });
  });

  pi.on("tool_execution_end", async (event) => {
    const tool = active?.tools.get(event.toolCallId);
    if (!tool || !active) return;

    active.tools.delete(event.toolCallId);
    restoreTraceParentEnv(active, event.toolCallId);
    await safeEnd(tool, {
      outputs: { result: event.result },
      error: event.isError ? "Tool execution failed" : undefined,
      metadata: { isError: event.isError },
    });
  });

  pi.on("turn_end", async (event) => {
    if (!active) return;
    const turn = active.turns.get(event.turnIndex) ?? active.currentTurn;

    await safeEnd(active.currentLlm, {
      outputs: { message: event.message },
      metadata: {
        usage_metadata: extractUsageMetadata(event.message),
      },
    });
    active.currentLlm = undefined;

    await safeEnd(turn, {
      outputs: { message: event.message, toolResults: event.toolResults },
    });
    if (turn === active.currentTurn) active.currentTurn = undefined;
  });

  pi.on("agent_end", async (event, ctx) => {
    if (!active) return;

    for (const tool of active.tools.values()) {
      await safeEnd(tool, { error: "Pi run ended before tool_execution_end" });
    }
    active.tools.clear();

    for (const toolCallId of [...active.envRestores.keys()]) {
      restoreTraceParentEnv(active, toolCallId);
    }
    if (active.pendingLlm) {
      const pending = active.pendingLlm;
      active.pendingLlm = undefined;
      await startLlmRun(active, active.currentTurn ?? active.root, pending);
    }
    await safeEnd(active.currentLlm, {
      error: "Pi run ended before LLM message finalized",
    });
    for (const turn of active.turns.values()) {
      await safeEnd(turn, { outputs: { incomplete: true } });
    }

    const root = active.root;
    await safeEnd(root, {
      outputs: { messages: event.messages, context_usage: ctx.getContextUsage() },
    });

    active = undefined;
    ctx.ui.setStatus(STATUS_KEY, "LangSmith: traced");
  });

  pi.on("session_shutdown", async (_event, ctx) => {
    if (active) {
      if (active.pendingLlm) {
        const pending = active.pendingLlm;
        active.pendingLlm = undefined;
        await startLlmRun(active, active.currentTurn ?? active.root, pending);
      }
      await safeEnd(active.currentLlm, {
        error: "Pi session shut down before LLM message finalized",
      });
      await safeEnd(active.root, {
        outputs: { shutdown: true },
        error: "Pi session shut down before run completed",
      });

      for (const toolCallId of [...active.envRestores.keys()]) {
        restoreTraceParentEnv(active, toolCallId);
      }

      active = undefined;
    }
    await client.awaitPendingTraceBatches();
    ctx.ui.setStatus(STATUS_KEY, undefined);
  });
}

import * as fs from "node:fs/promises";
import * as os from "node:os";
import * as path from "node:path";

import { z } from "zod";

const ReplicaSchema = z.preprocess(
  (value) => {
    if (value == null || typeof value !== "object" || Array.isArray(value)) {
      return value;
    }

    const replica = value as Record<string, unknown>;
    return {
      api_url: replica.api_url ?? replica.apiUrl,
      api_key: replica.api_key ?? replica.apiKey,
      project: replica.project ?? replica.projectName,
      updates: replica.updates,
    };
  },
  z.object({
    api_url: z.string().optional(),
    api_key: z.string().optional(),
    project: z.string().optional(),
    updates: z.record(z.string(), z.unknown()).optional(),
  }),
);

export const ConfigSchema = z.object({
  // TRACE_TO_LANGSMITH == true
  enabled: z.boolean(),

  // LANGSMITH_PI_API_KEY or LANGSMITH_API_KEY
  api_key: z.string().optional(),

  // LANGSMITH_PI_ENDPOINT or LANGSMITH_ENDPOINT
  api_url: z.string().optional(),

  // LANGSMITH_PI_PROJECT or LANGSMITH_PROJECT
  project: z.string().optional(),

  // LANGSMITH_PI_METADATA
  metadata: z.record(z.string(), z.unknown()).optional(),

  // LANGSMITH_PI_RUNS_ENDPOINTS
  replicas: z.array(ReplicaSchema).optional(),
});

const PartialConfigSchema = ConfigSchema.partial();

export type Config = z.infer<typeof ConfigSchema>;

function parseBoolean(value: unknown): boolean | undefined {
  if (typeof value === "boolean") return value;
  if (typeof value !== "string") return undefined;

  const normalized = value.trim().toLowerCase();
  if (["1", "true", "yes", "on"].includes(normalized)) return true;
  if (["0", "false", "no", "off"].includes(normalized)) return false;
  return undefined;
}

function parseJson(value: unknown): Record<string, unknown> | undefined {
  if (typeof value !== "string") return undefined;
  if (value.trim().length === 0) return undefined;
  try {
    return JSON.parse(value);
  } catch (error) {
    return undefined;
  }
}

const stripUndefined = <T extends Record<string, unknown>>(value: T): Partial<T> => {
  return Object.fromEntries(
    Object.entries(value).filter(([, entry]) => entry !== undefined),
  ) as Partial<T>;
};

async function readConfigFile(file: string): Promise<Partial<Config> | undefined> {
  try {
    const data = await fs.readFile(file, "utf-8");
    return PartialConfigSchema.parse(JSON.parse(data));
  } catch {
    return undefined;
  }
}

function getVar(suffix: string, env: Record<string, string | undefined>): string | undefined {
  return env[`LANGSMITH_PI_${suffix}`] ?? env[`LANGSMITH_${suffix}`];
}

const readConfigEnv = (env: Record<string, string | undefined>): Partial<Config> => {
  const enabled = parseBoolean(env.TRACE_TO_LANGSMITH);

  return stripUndefined(
    PartialConfigSchema.parse({
      enabled,
      api_key: getVar("API_KEY", env),
      api_url: getVar("ENDPOINT", env),
      project: getVar("PROJECT", env),
      metadata: parseJson(getVar("METADATA", env)),
      replicas: parseJson(getVar("RUNS_ENDPOINTS", env)),
    }),
  );
};

const getHomeDir = () => process.env.HOME ?? os.homedir();

export async function getConfig(options?: {
  home: string;
  cwd: string;
  env: Record<string, string | undefined>;
}) {
  const home = options?.home ?? getHomeDir();
  const cwd = options?.cwd ?? process.cwd();
  const env = options?.env ?? process.env;

  const envConfig = readConfigEnv(env);
  const [globalConfig, localConfig] = await Promise.all([
    readConfigFile(path.join(home, ".pi", "langsmith.json")),
    readConfigFile(path.join(cwd, ".pi", "langsmith.json")),
  ]);

  return ConfigSchema.parse({
    project: "pi-coding-agent",
    enabled: false,
    ...globalConfig,
    ...localConfig,
    ...envConfig,
  });
}

import { ExtensionAPI, ExtensionContext } from "@earendil-works/pi-coding-agent";
import * as fs from "node:fs/promises";

export default async function (pi: ExtensionAPI) {
  function createRecord(eventName: string) {
    return async function record(arg: unknown, ctx: ExtensionContext) {
      await fs.appendFile(
        "langsmith.jsonl",
        `${JSON.stringify([
          Date.now(),
          eventName,
          arg,
          {
            cwd: ctx.cwd,
            model: ctx.model,
            getContextUsage: ctx.getContextUsage?.(),
          },
        ])}\n`,
      );
    };
  }

  pi.on("resources_discover", createRecord("resources_discover"));
  pi.on("session_start", createRecord("session_start"));
  pi.on("session_before_switch", createRecord("session_before_switch"));
  pi.on("session_before_fork", createRecord("session_before_fork"));
  pi.on("session_before_compact", createRecord("session_before_compact"));
  pi.on("session_compact", createRecord("session_compact"));
  pi.on("session_shutdown", createRecord("session_shutdown"));
  pi.on("session_before_tree", createRecord("session_before_tree"));
  pi.on("session_tree", createRecord("session_tree"));
  pi.on("context", createRecord("context"));
  pi.on("before_provider_request", createRecord("before_provider_request"));
  pi.on("after_provider_response", createRecord("after_provider_response"));
  pi.on("before_agent_start", createRecord("before_agent_start"));
  pi.on("agent_start", createRecord("agent_start"));
  pi.on("agent_end", createRecord("agent_end"));
  pi.on("turn_start", createRecord("turn_start"));
  pi.on("turn_end", createRecord("turn_end"));
  pi.on("message_start", createRecord("message_start"));
  // No need to record message_update, only useful for streaming
  // pi.on("message_update", createRecord("message_update"));
  pi.on("message_end", createRecord("message_end"));
  pi.on("tool_execution_start", createRecord("tool_execution_start"));
  pi.on("tool_execution_update", createRecord("tool_execution_update"));
  pi.on("tool_execution_end", createRecord("tool_execution_end"));
  pi.on("model_select", createRecord("model_select"));
  pi.on("thinking_level_select", createRecord("thinking_level_select"));
  pi.on("tool_call", createRecord("tool_call"));
  pi.on("tool_result", createRecord("tool_result"));
  pi.on("user_bash", createRecord("user_bash"));
  pi.on("input", createRecord("input"));
}

import { it, vi } from "vitest";
import * as fs from "node:fs";
import { Client } from "langsmith";
import type { ExtensionAPI, ExtensionContext } from "@earendil-works/pi-coding-agent";

import extension from "../src/index";

it("replay", { timeout: 60_000 }, async () => {
  const file = await fs.promises.readFile("langsmith.jsonl", "utf-8");
  const lines = file.trim().split("\n");
  const events = lines.map((line) => JSON.parse(line));

  const handlers: Record<
    string,
    Array<(arg: unknown, context: ExtensionContext) => Promise<void>>
  > = {};

  const pi = {
    on: (
      eventName: string,
      handler: (arg: unknown, context: ExtensionContext) => Promise<void>,
    ) => {
      handlers[eventName] ??= [];
      handlers[eventName].push(handler);
    },
    registerCommand: (...args: unknown[]) => vi.fn(),
  } as unknown as ExtensionAPI;

  const client = new Client();

  // Register handlers
  await extension(pi, { client });

  // Invoke events from replay
  let lastTime: number | undefined = undefined;
  for (const [currTime, eventName, arg, ctx] of events) {
    let wait = lastTime !== undefined ? Math.max(0, currTime - lastTime) : 0;
    if (eventName === "session_shutdown") wait = 0; // Don't wait after shutdown event

    // if (wait > 0) await new Promise((resolve) => setTimeout(resolve, wait));

    for (const handler of handlers[eventName] ?? [])
      await handler(arg, {
        ui: { setStatus: vi.fn() },
        ...ctx,
        getContextUsage: () => ctx?.getContextUsage,
      });

    lastTime = currTime;
  }

  await client.awaitPendingTraceBatches();
});
